44	/**
45	 * Responses that players can select themselves in this form.
46	 */
47	const playerEditableResponses = new Set<PlayerResponse>([
48	    PlayerResponse.Yes,
49	    PlayerResponse.No,
50	    PlayerResponse.Dunno,
51	]);
