53	/**
54	 * Returns the initial response value used by the editable select input.
55	 *
56	 * Player invitations can carry admin-only response values (for example
57	 * `Excused`) that should still be displayed in the summary, but players can
58	 * only submit Yes/No/Dunno from this form.
59	 *
60	 * @param response - Incoming invitation response from query details.
61	 * @returns The player-editable response value for the form select.
62	 */
63	function getInitialPlayerResponse(responseInput: GameInvitationResponseDetails['response']) {
64	    const response = responseInput &&
65	        playerEditableResponses.has(responseInput) ? responseInput : PlayerResponse.Yes;
66	
67	    return response;
68	}
