75	export const GameInvitationResponseForm = ({
76	    details,
77	    onSubmitGameInvitationResponse,
78	}: Props) => {
79	    const response = getInitialPlayerResponse(details.response);
80	    const [currentResponse, setCurrentResponse] = useState(details.response);
81	    const [currentComment, setCurrentComment] = useState(details.comment);
82	    const [canSubmitWithoutChanges, setCanSubmitWithoutChanges] = useState(!details.response);
83	
84	    const form = useForm<FormValues>({
85	        initialValues: {
86	            response,
87	            goalie: details.goalie ?? false,
88	            comment: details.comment ?? '',
89	        },
90	        validate: zod4Resolver(formSchema),
91	        validateInputOnBlur: true,
92	    });
93	
94	    /**
95	     * The form is dirty if the user has changed a field, or if there is no
96	     * saved response yet. In that case, submission is allowed without
97	     * interaction so users can quickly confirm the default Yes value. Once a
98	     * response has been saved, the button should disable again until the form
99	     * changes.
100	     */
101	    const isFormDirty = form.isDirty() || canSubmitWithoutChanges;
102	
103	    const handleSubmit = async (values: FormValues) => {
104	        const id = notifications.show({
105	            loading: true,
106	            title: 'Saving response',
107	            message: 'Saving your response...',
108	            autoClose: false,
109	            withCloseButton: false,
110	        });
111	
112	        try {
113	            await onSubmitGameInvitationResponse({
114	                token: details.token,
115	                response: values.response,
116	                goalie: values.goalie,
117	                comment: values.comment?.trim() ?? null,
