119	
120	            setCurrentResponse(values.response);
121	            setCurrentComment(values.comment?.trim() ?? '');
122	            setCanSubmitWithoutChanges(false);
123	
124	            notifications.update({
125	                id,
126	                color: 'teal',
127	                title: 'Response saved',
128	                message: 'Your response has been updated.',
129	                icon: <IconCheck size={config.notificationIconSize} />,
130	                loading: false,
131	                autoClose: config.notificationAutoClose,
132	            });
133	        } catch (error) {
134	            captureUnexpectedError(error, {
135	                layer: 'client',
136	                component: 'GameInvitationResponseForm',
137	                action: 'submitResponse',
138	                route: '/footy/game/[id]',
139	                extra: {
140	                    playerId: details.playerId,
141	                    gameDayId: details.gameDayId,
142	                    response: values.response,
143	                },
144	            });
145	            const message = error instanceof Error ? error.message : 'Failed to save response';
146	            notifications.update({
147	                id,
148	                color: 'red',
149	                title: 'Error',
150	                message,
151	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
152	                loading: false,
153	                autoClose: false,
154	                withCloseButton: true,
155	            });
156	        }
